/**
 * TLog SDK v1.2 — TALON 組み込み用（旧API完全互換・Proxy方式）
 */
(function(global) {
  'use strict';

  var _config = {};
  var _traceId = null;
  var _seq = 0;
  var _queue = [];  // startTrace完了前のログをバッファ

  function flushQueue() {
    var q = _queue.slice(); _queue = [];
    q.forEach(function(fn) { fn(); });
  }

  function post(path, body) {
    if (!_config.serverUrl) return Promise.resolve();
    var label = path === '/sdk/log'         ? '[TLog] LOG送信     ▶ ' + (body.eventType||'') + ' | ' + (body.screenName||'') + ' | seq=' + (body.seqNo||0)
              : path === '/sdk/consolelog'  ? '[TLog] CONSOLE送信 ▶ [' + (body.level||'').toUpperCase() + '] ' + (body.message||'').slice(0,80)
              : path === '/sdk/screenshot'  ? '[TLog] SCREENSHOT送信 ▶ ' + (body.screenId||body.screenName||'')
              : '[TLog] POST ' + path;
    console.log(label);
    return fetch(_config.serverUrl + path, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'x-api-key': _config.apiKey },
      body: JSON.stringify(body),
    }).then(function(res) {
      console.log('[TLog] 送信OK  ◀ ' + path + ' status=' + res.status);
      return res;
    }).catch(function(e) { console.warn('[TLog] 送信失敗 ✗ ' + path + ':', e.message); });
  }

  // ─── TLog 本体 ───
  var TLogBase = {
    init: function(config) {
      _config = Object.assign({ serverUrl: 'http://192.168.1.11:3099', projectId: 'legacy' }, config);
      console.log('[TLog] 初期化完了 project=' + _config.projectId);
      if (_config.autoStart) {
        TLogBase.startTrace({ userId: 'auto', label: '' });
      }
    },
    startTrace: function(opts) {
      opts = opts || {};
      return post('/sdk/trace/start', {
        projectId: _config.projectId,
        operatorId: opts.userId || 'unknown',
        metadata: opts.meta || {},
        label: opts.label || '',
      }).then(function(res) {
        if (!res) return;
        return res.json().then(function(data) {
          _traceId = data.traceId; _seq = 0;
          console.log('[TLog] Trace開始:', _traceId);
          flushQueue();
        });
      });
    },
    stopTrace: function() {
      if (!_traceId) return Promise.resolve();
      return post('/sdk/trace/stop', { traceId: _traceId, projectId: _config.projectId })
        .then(function() { console.log('[TLog] Trace終了:', _traceId); _traceId = null; });
    },
    log: function(eventType, screenName, elementId, payload) {
      if (!_traceId) {
        _queue.push(function() { TLogBase.log(eventType, screenName, elementId, payload); });
        return;
      }
      _seq++;
      return post('/sdk/log', {
        traceId: _traceId, projectId: _config.projectId,
        eventType: eventType || 'ACTION', screenName: screenName || '',
        elementId: elementId || '', seqNo: _seq, payload: payload || {},
      });
    },
    getTraceId: function() { return _traceId; },
    // 旧API互換
    screenLoad: function(screenId, screenName) {
      TLogBase.log('SCREEN_LOAD', screenId, '', { label: screenName });
    },
    bootstrap:     function(o) { console.log('[TLog] bootstrap:', o); },
    screenCapture: function(screenId, label) {
      TLogBase.log('SCREENSHOT', screenId, '', { label: label || '' });
      captureScreen(screenId, _seq);
    },
    action: function(screenId, elementId, payload) {
      TLogBase.log('ACTION', screenId, elementId, payload || {});
    },
  };

  // TLog に Proxy を適用 → 未定義メソッドを全部ダミーで吸収
  global.TLog = (typeof Proxy !== 'undefined')
    ? new Proxy(TLogBase, {
        get: function(target, prop) {
          if (prop in target) return target[prop];
          return function() {
            console.log('[TLog] 未実装メソッド呼び出し（無視）: TLog.' + String(prop), arguments);
          };
        }
      })
    : TLogBase;

  // ─── html2canvas 動的ロード ───
  var _html2canvasReady = false;
  (function() {
    if (typeof html2canvas !== 'undefined') { _html2canvasReady = true; return; }
    var s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js';
    s.onload = function() { _html2canvasReady = true; console.log('[TLog] html2canvas ロード完了'); };
    document.head.appendChild(s);
  })();

  function captureScreen(screenId, seqNo) {
    if (!_traceId) return;
    var h2c = (typeof html2canvas !== 'undefined') ? html2canvas : null;
    if (!h2c) { console.warn('[TLog] html2canvas 未準備'); return; }
    h2c(document.body, { scale: 0.5, useCORS: true, logging: false }).then(function(canvas) {
      canvas.toBlob(function(blob) {
        if (!blob) return;
        var fd = new FormData();
        fd.append('file', blob, 'screenshot.png');
        fd.append('traceId', _traceId);
        fd.append('projectId', _config.projectId);
        fd.append('screenId', screenId || '');
        fd.append('seqNo', String(seqNo || _seq));
        fetch(_config.serverUrl + '/sdk/screenshot', {
          method: 'POST',
          headers: { 'x-api-key': _config.apiKey },
          body: fd,
        }).then(function(r) {
          console.log('[TLog] SCREENSHOT送信OK ◀ status=' + r.status);
        }).catch(function(e) { console.warn('[TLog] SCREENSHOT送信失敗:', e.message); });
      }, 'image/png');
    });
  }

  // ─── console capture ───
  (function() {
    var methods = ['log','warn','error','info'];
    methods.forEach(function(m) {
      var orig = console[m].bind(console);
      console[m] = function() {
        orig.apply(console, arguments);
        if (!_traceId) return;
        var msg = Array.prototype.slice.call(arguments).map(function(a) {
          try { return typeof a === 'object' ? JSON.stringify(a) : String(a); } catch(e) { return String(a); }
        }).join(' ');
        if (msg.indexOf('192.168.1.11') !== -1 || msg.indexOf('[TLog]') !== -1) return;
        post('/sdk/consolelog', { traceId: _traceId, projectId: _config.projectId, level: m, message: msg, seqNo: _seq, timestamp: Date.now() });
      };
    });
  })();

  // ─── TLogAutoInstrument 本体 ───
  var TLogAutoInstrumentBase = {
    init: function(screenId, opts) {
      opts = opts || {};
      var sid = (typeof screenId === 'string') ? screenId : (opts.screenId || '');
      console.log('[TLogAutoInstrument] init screenId=' + sid);

      // SCREEN_LOAD を自動送信
      TLogBase.log('SCREEN_LOAD', sid, '', { label: opts.screenName || sid });
      // 画面ロード時スクショ（500ms遅延でレンダリング完了後）
      setTimeout(function() { captureScreen(sid, _seq); }, 500);

      // クリックリスナー（全ボタン・a要素）
      document.addEventListener('click', function(e) {
        if (!_traceId) return;
        var t = e.target || e.srcElement;
        if (!t) return;
        var tag = t.tagName ? t.tagName.toUpperCase() : '';
        if (tag === 'BUTTON' || tag === 'INPUT' || tag === 'A' ||
            t.getAttribute('onclick') || t.getAttribute('data-ui-block-type')) {
          var elId = t.id || t.name || t.value || '';
          var label = t.value || t.textContent || t.innerText || elId;
          TLogBase.log('CLICK', sid, elId, { label: String(label).trim().slice(0, 100) });
        }
      }, true);

      // inputリスナー（テキスト入力・セレクト）
      document.addEventListener('change', function(e) {
        if (!_traceId) return;
        var t = e.target || e.srcElement;
        if (!t) return;
        var tag = t.tagName ? t.tagName.toUpperCase() : '';
        if (tag === 'INPUT' || tag === 'SELECT' || tag === 'TEXTAREA') {
          TLogBase.log('INPUT', sid, t.id || t.name || '', { value: t.value || '' });
        }
      }, true);
    },
    instrument:        function(el, o) { console.log('[TLogAutoInstrument] instrument:', o); },
    click:             function(id, label, p) { TLogBase.log('CLICK', '', id, Object.assign({ label: label||'' }, p||{})); },
    input:             function(id, val, p)   { TLogBase.log('INPUT', '', id, Object.assign({ value: val||'' }, p||{})); },
    attachRowButtonLog: function(el, screenId, label) {
      if (!el) return;
      var domEl = (el[0] && el[0].addEventListener) ? el[0] : el;
      if (typeof domEl.addEventListener !== 'function') return;
      domEl.addEventListener('click', function() {
        TLogBase.log('CLICK', screenId, domEl.id || label || '', { label: label || '' });
      });
    },
  };

  // TLogAutoInstrument にも Proxy → 未定義を全部吸収
  global.TLogAutoInstrument = (typeof Proxy !== 'undefined')
    ? new Proxy(TLogAutoInstrumentBase, {
        get: function(target, prop) {
          if (prop in target) return target[prop];
          return function() {
            console.log('[TLogAutoInstrument] 未実装メソッド（無視）: TLogAutoInstrument.' + String(prop), arguments);
          };
        }
      })
    : TLogAutoInstrumentBase;

  console.log('[TLogAutoInstrument] 初期化完了');

})(window);
